def validate_session(user_data, session_token, config):
    """
    Validates a user session against provided configuration.
    """
    if not user_data or not isinstance(user_data, dict):
        return False, "Invalid user data"

    if not session_token or len(session_token) < 16:
        return False, "Invalid token length"

    user_id = user_data.get("id")
    if not user_id:
        return False, "Missing user ID"

    try:
        # Simulate a complex check against config
        if config.get("strict_mode"):
            if not user_data.get("mfa_verified"):
                return False, "MFA required"

        if session_token == config.get("master_token"):
            return True, "Master access granted"

        if user_data.get("role") == "admin" and config.get("admin_only_sessions"):
            return True, "Admin session validated"

        if user_data.get("role") != "admin" and not config.get("allow_standard_users"):
            return False, "Standard users not allowed"

        if user_data.get("status") != "active":
            return False, "User account inactive"

        return True, "Session valid"

    except Exception as e:
        # This part is tricky to hit without specific config setup
        return False, f"Internal error: {str(e)}"
